{
  "name": "SciTech Tutor AI",
  "description": "A focused AI assistant for students specializing in Science (Physics, Chemistry, Biology) and Computer Science. Designed to provide step-by-step solutions while maintaining strict subject guardrails.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string;
  timestamp: number;
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "SciTech Tutor", an expert academic assistant for students.
Your expertise is strictly limited to:
1. Pure Sciences: Physics, Chemistry, Biology.
2. Technology: Computer Science, Programming, Engineering.
3. Logical Reasoning related to these fields.

CRITICAL GUARDRAILS:
- DO NOT answer questions about Mathematics (Algebra, Calculus, Geometry) as a standalone subject. If a math calculation is part of a Physics/Chemistry problem, you may solve it, but do not solve pure math problems.
- DO NOT answer questions about Social Sciences (History, Geography, Political Science, Economics, etc.).
- DO NOT answer questions about Hindi, English, or any other languages/literature.
- If a user asks something outside your scope, politely say: "I specialize only in Science and Technology. I cannot help with [Subject Name] questions. Please ask me about Physics, Chemistry, Biology, or Computer Science!"

Formatting:
- Use Markdown for responses.
- Use bold for key terms.
- Provide step-by-step explanations.
- Be encouraging but academic.
`;

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async solveQuestion(prompt: string, imageBase64?: string): Promise<string> {
    const model = 'gemini-3-flash-preview';

    const parts: any[] = [{ text: prompt }];

    if (imageBase64) {
      parts.unshift({
        inlineData: {
          mimeType: 'image/jpeg',
          data: imageBase64.split(',')[1] || imageBase64,
        },
      });
    }

    try {
      const response: GenerateContentResponse = await this.ai.models.generateContent({
        model,
        contents: { parts },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.7,
        },
      });

      return response.text || "I couldn't generate a response. Please try again.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      if (error instanceof Error && error.message.includes("404")) {
          return "Error: API key or model not found. Please check your configuration.";
      }
      return "I'm having trouble connecting to my brain right now. Please try again later!";
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from './geminiService';
import { Message, ChatSession } from './types';
import { ChatBubble } from './components/ChatBubble';
import { Sidebar } from './components/Sidebar';
import { 
  Send, 
  Paperclip, 
  Image as ImageIcon, 
  X, 
  BookOpen, 
  Microscope, 
  Cpu, 
  PlusCircle,
  AlertCircle
} from 'lucide-react';

const gemini = new GeminiService();

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [input, setInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    // Initialize first session if none exists
    if (sessions.length === 0) {
      createNewSession();
    }
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentSession?.messages]);

  const createNewSession = () => {
    const newId = Date.now().toString();
    const newSession: ChatSession = {
      id: newId,
      title: 'New Question',
      messages: []
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newId);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendMessage = async () => {
    if ((!input.trim() && !selectedImage) || isLoading || !currentSessionId) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      image: selectedImage || undefined,
      timestamp: Date.now(),
    };

    // Update session with user message
    setSessions(prev => prev.map(s => 
      s.id === currentSessionId 
        ? { ...s, messages: [...s.messages, userMsg], title: input.slice(0, 30) || 'Image Question' } 
        : s
    ));

    const prompt = input;
    const img = selectedImage;

    setInput('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      const response = await gemini.solveQuestion(prompt, img || undefined);

      const modelMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response,
        timestamp: Date.now(),
      };

      setSessions(prev => prev.map(s => 
        s.id === currentSessionId 
          ? { ...s, messages: [...s.messages, modelMsg] } 
          : s
      ));
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar 
        sessions={sessions} 
        activeId={currentSessionId} 
        onSelect={setCurrentSessionId} 
        onNew={createNewSession}
      />

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col relative h-full">
        {/* Header */}
        <header className="h-16 border-b bg-white flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <BookOpen size={20} />
            </div>
            <div>
              <h1 className="font-bold text-slate-800 leading-tight">SciTech Tutor</h1>
              <p className="text-xs text-slate-500">Science & Tech Specialist</p>
            </div>
          </div>
          <div className="hidden md:flex gap-4 text-xs font-medium text-slate-500">
            <div className="flex items-center gap-1"><Microscope size={14} /> Physics</div>
            <div className="flex items-center gap-1"><Cpu size={14} /> CS</div>
            <div className="flex items-center gap-1 text-red-400 opacity-60"><AlertCircle size={14} /> No Math/Arts</div>
          </div>
        </header>

        {/* Messages Container */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6">
          {currentSession?.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center max-w-2xl mx-auto space-y-6">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600">
                <PlusCircle size={40} />
              </div>
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Ask Your Science Question</h2>
                <p className="text-slate-500 mt-2">
                  Snap a photo of your homework or type your question. 
                  I specialize in Physics, Chemistry, Biology, and Computer Science.
                </p>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
                <button 
                  onClick={() => setInput("Explain the process of photosynthesis step by step.")}
                  className="p-4 bg-white border rounded-xl text-left hover:border-indigo-300 hover:shadow-sm transition-all text-sm text-slate-700"
                >
                  "Explain the process of photosynthesis..."
                </button>
                <button 
                  onClick={() => setInput("How do I implement a binary search tree in Python?")}
                  className="p-4 bg-white border rounded-xl text-left hover:border-indigo-300 hover:shadow-sm transition-all text-sm text-slate-700"
                >
                  "How do I implement a binary search tree..."
                </button>
              </div>
            </div>
          ) : (
            currentSession?.messages.map((msg) => (
              <ChatBubble key={msg.id} message={msg} />
            ))
          )}
          {isLoading && (
            <div className="flex gap-4 animate-pulse">
              <div className="w-8 h-8 rounded-full bg-slate-200"></div>
              <div className="flex-1 space-y-2">
                <div className="h-4 bg-slate-200 rounded w-1/4"></div>
                <div className="h-4 bg-slate-200 rounded w-3/4"></div>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 md:p-6 bg-white border-t">
          <div className="max-w-4xl mx-auto">
            {selectedImage && (
              <div className="mb-4 relative inline-block">
                <img src={selectedImage} alt="Selected" className="h-32 rounded-lg border shadow-sm" />
                <button 
                  onClick={() => setSelectedImage(null)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white p-1 rounded-full shadow-md"
                >
                  <X size={14} />
                </button>
              </div>
            )}
            <div className="relative flex items-end gap-2 bg-slate-100 rounded-2xl p-2 border border-slate-200 focus-within:border-indigo-400 focus-within:ring-2 focus-within:ring-indigo-100 transition-all">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="p-3 text-slate-500 hover:text-indigo-600 hover:bg-white rounded-xl transition-all"
                title="Attach Question Photo"
              >
                <ImageIcon size={20} />
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept="image/*" 
                onChange={handleImageUpload}
              />
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSendMessage();
                  }
                }}
                placeholder="Ask about Physics, Chemistry, Biology, or Computer Science..."
                className="flex-1 bg-transparent border-none focus:ring-0 text-slate-800 py-3 px-2 resize-none max-h-48"
                rows={1}
              />
              <button 
                onClick={handleSendMessage}
                disabled={(!input.trim() && !selectedImage) || isLoading}
                className={`p-3 rounded-xl transition-all ${
                  (!input.trim() && !selectedImage) || isLoading 
                    ? 'bg-slate-200 text-slate-400' 
                    : 'bg-indigo-600 text-white shadow-lg hover:bg-indigo-700 active:scale-95'
                }`}
              >
                <Send size={20} />
              </button>
            </div>
            <p className="text-[10px] text-center text-slate-400 mt-2">
              Note: SciTech Tutor is specialized for Science and Technology subjects only.
            </p>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Message } from '../types';
import { User, Cpu, BookOpen } from 'lucide-react';

interface ChatBubbleProps {
  message: Message;
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message }) => {
  const isModel = message.role === 'model';

  return (
    <div className={`flex gap-4 ${isModel ? 'justify-start' : 'justify-end'}`}>
      {isModel && (
        <div className="w-8 h-8 rounded-lg bg-indigo-600 text-white flex items-center justify-center shrink-0">
          <BookOpen size={16} />
        </div>
      )}

      <div className={`max-w-[85%] md:max-w-[70%] space-y-2`}>
        <div className={`rounded-2xl p-4 ${
          isModel 
            ? 'bg-white border border-slate-200 text-slate-800' 
            : 'bg-indigo-600 text-white shadow-md'
        }`}>
          {message.image && (
            <img 
              src={message.image} 
              alt="Question" 
              className="max-h-64 rounded-lg mb-3 border border-indigo-300/30" 
            />
          )}
          <div className="prose prose-sm max-w-none prose-slate">
            {message.text.split('\n').map((line, i) => (
              <p key={i} className="mb-2 last:mb-0 leading-relaxed">
                {line}
              </p>
            ))}
          </div>
        </div>
        <div className={`text-[10px] text-slate-400 ${!isModel ? 'text-right' : ''}`}>
          {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </div>
      </div>

      {!isModel && (
        <div className="w-8 h-8 rounded-lg bg-slate-200 text-slate-600 flex items-center justify-center shrink-0">
          <User size={16} />
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { ChatSession } from '../types';
import { Plus, MessageSquare, BookOpen, Trash2 } from 'lucide-react';

interface SidebarProps {
  sessions: ChatSession[];
  activeId: string | null;
  onSelect: (id: string) => void;
  onNew: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ sessions, activeId, onSelect, onNew }) => {
  return (
    <aside className="w-72 bg-slate-900 text-slate-300 hidden md:flex flex-col border-r border-slate-800 shrink-0">
      <div className="p-4 border-b border-slate-800">
        <button 
          onClick={onNew}
          className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white py-2.5 px-4 rounded-xl transition-all font-medium shadow-sm"
        >
          <Plus size={18} />
          New Question
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-3 space-y-1 custom-scrollbar">
        <div className="px-3 mb-2">
          <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Recent History</h3>
        </div>
        {sessions.map((session) => (
          <button
            key={session.id}
            onClick={() => onSelect(session.id)}
            className={`w-full flex items-center gap-3 p-3 rounded-lg text-sm text-left transition-all ${
              activeId === session.id 
                ? 'bg-slate-800 text-white shadow-inner' 
                : 'hover:bg-slate-800/50'
            }`}
          >
            <MessageSquare size={16} className={activeId === session.id ? 'text-indigo-400' : 'text-slate-500'} />
            <span className="truncate flex-1">{session.title}</span>
          </button>
        ))}
      </div>

      <div className="p-4 border-t border-slate-800 bg-slate-900/50">
        <div className="flex items-center gap-3 p-2 bg-slate-800 rounded-lg">
          <div className="w-8 h-8 rounded bg-indigo-500/20 text-indigo-400 flex items-center justify-center">
            <BookOpen size={16} />
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-xs font-semibold text-white truncate">Student Portal</p>
            <p className="text-[10px] text-slate-500">Free Academic Tier</p>
          </div>
        </div>
      </div>
    </aside>
  );
};

